import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PollenLevel {
  day: string;
  count: number;
  severity: string;
}

interface PollenData {
  location: string;
  currentLevel: {
    pollenType: string;
    count: number;
    severity: string;
  };
  dailyLevels: PollenLevel[];
}

export default function Widget() {
  const pollenData = response.data as PollenData;
  const { location, currentLevel, dailyLevels } = pollenData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ mt: 0.5, color: '#1976D2' }}>
              {currentLevel.pollenType} Pollen
            </Typography>
            <Typography variant="body2" fontWeight={500}>
              Current Count: {currentLevel.count}
            </Typography>
            <Chip
              label={currentLevel.severity}
              sx={{ mt: 0.5, fontSize: '12px', backgroundColor: '#FFC107', color: '#FFFFFF' }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 140 }}>
            <BarChart
              height={120}
              series={[
                {
                  data: dailyLevels.map(d => d.count),
                  color: '#FF5722',
                },
              ]}
              xAxis={[
                {
                  data: dailyLevels.map(d => d.day),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                },
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
